"""
MKT Luke chapters 10-12 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-luke-10-12.py
Part 2 of 3 covering Luke 7-15.
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

# Key term notes:
# αἰώνιος ζωή (10:25) = "eternal life" — here denotes quality of the coming age, not merely duration
# πλησίον (10:27ff) = "neighbour" — preserved in all tiers
# πνεῦμα = Holy Spirit (divine agent, capitalised); demon spirit (lower-case)
# βασιλεία τοῦ θεοῦ = kingdom of God throughout
# ἄφες ἡμῖν τὰς ἁμαρτίας (11:4) = "forgive us our sins" — ἁμαρτία = sin, not just debt
# γέεννα (12:5) = "Gehenna" (kept as hell in M/T but noted)
# Divine passive throughout 12: e.g., "will be required" = God demanding account

LUKE_10_12 = {
 "10": {
  "1": {"L":"After this the Lord appointed seventy-two others and sent them on ahead of him, two by two, into every town and place where he himself was about to go.","M":"After this the Lord appointed seventy-two others and sent them two by two ahead of him to every town and place where he was about to go.","T":"After this the Lord appointed seventy-two others and sent them ahead of him in pairs to every town and place he was about to visit."},
  "2": {"L":"And he said to them: The harvest is plentiful, but the laborers are few. Therefore pray earnestly to the Lord of the harvest to send out laborers into his harvest.","M":"He told them: The harvest is plentiful, but the workers are few. Ask the Lord of the harvest, therefore, to send out workers into his harvest field.","T":"He told them: The harvest is enormous but the workers are few. So ask the Lord of the harvest to send workers out into his fields."},
  "3": {"L":"Go your way; behold, I am sending you out as lambs in the midst of wolves.","M":"Go! I am sending you out like lambs among wolves.","T":"Go—I am sending you out like lambs among wolves."},
  "4": {"L":"Carry no moneybag, no knapsack, no sandals, and greet no one on the road.","M":"Do not take a purse or bag or sandals; and do not greet anyone on the road.","T":"Take no money bag, no pack, no sandals—and don't stop to greet anyone along the road."},
  "5": {"L":"Whatever house you enter, first say: Peace be to this house!","M":"When you enter a house, first say, Peace to this house.","T":"When you enter a home, first say: Peace to this house."},
  "6": {"L":"And if a son of peace is there, your peace will rest on him. But if not, it will return to you.","M":"If someone who promotes peace is there, your peace will rest on them; if not, it will return to you.","T":"If someone there is receptive to peace, your peace will settle on them. If not, it will return to you."},
  "7": {"L":"And remain in the same house, eating and drinking what they provide, for the laborer deserves his wages. Do not go from house to house.","M":"Stay there, eating and drinking whatever they give you, for the worker deserves his wages. Do not move around from house to house.","T":"Stay in that same house, eating and drinking whatever they provide—the worker deserves their pay. Don't keep moving from house to house."},
  "8": {"L":"Whenever you enter a town and they receive you, eat what is set before you.","M":"When you enter a town and are welcomed, eat what is offered to you.","T":"Whenever you enter a town and are welcomed, eat whatever is placed before you."},
  "9": {"L":"Heal the sick in it and say to them: The kingdom of God has come near to you.","M":"Heal the sick who are there and tell them, The kingdom of God has come near to you.","T":"Heal the sick there and tell them: The kingdom of God has drawn near to you."},
  "10": {"L":"But whenever you enter a town and they do not receive you, go into its streets and say:","M":"But when you enter a town and are not welcomed, go into its streets and say:","T":"But when you enter a town and are not welcomed, go into its streets and say:"},
  "11": {"L":"Even the dust of your town that clings to our feet we wipe off against you. Nevertheless know this, that the kingdom of God has come near.","M":"Even the dust of your town we wipe from our feet as a warning to you. Yet be sure of this: the kingdom of God has come near.","T":"Even the dust of your town we wipe from our feet—as a witness against you. But know this: the kingdom of God has come near."},
  "12": {"L":"I tell you, it will be more bearable on that day for Sodom than for that town.","M":"I tell you, it will be more bearable on that day for Sodom than for that town.","T":"I tell you, on that day Sodom will fare better than that town."},
  "13": {"L":"Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works done in you had been done in Tyre and Sidon, they would have repented long ago, sitting in sackcloth and ashes.","M":"Woe to you, Chorazin! Woe to you, Bethsaida! For if the miracles that were performed in you had been performed in Tyre and Sidon, they would have repented long ago, sitting in sackcloth and ashes.","T":"Woe to you, Chorazin! Woe to you, Bethsaida! If the mighty works done among you had been done in Tyre and Sidon, they would have turned to God long ago in sackcloth and ashes."},
  "14": {"L":"But it will be more bearable in the judgment for Tyre and Sidon than for you.","M":"But it will be more bearable for Tyre and Sidon at the judgment than for you.","T":"But at the judgment, Tyre and Sidon will be better off than you."},
  "15": {"L":"And you, Capernaum, will you be exalted to heaven? You shall be brought down to Hades.","M":"And you, Capernaum, will you be lifted to the heavens? No, you will go down to the depths.","T":"And you, Capernaum—do you think you will be lifted to heaven? You will be brought down to the depths."},
  "16": {"L":"The one who hears you hears me, and the one who rejects you rejects me, and the one who rejects me rejects him who sent me.","M":"Whoever listens to you listens to me; whoever rejects you rejects me; but whoever rejects me rejects him who sent me.","T":"Whoever listens to you listens to me. Whoever rejects you rejects me—and whoever rejects me rejects the one who sent me."},
  "17": {"L":"The seventy-two returned with joy, saying: Lord, even the demons are subject to us in your name!","M":"The seventy-two returned with joy and said: Lord, even the demons submit to us in your name!","T":"The seventy-two came back full of joy: Lord, even the demons submit to us when we use your name!"},
  "18": {"L":"And he said to them: I saw Satan fall like lightning from heaven.","M":"He replied: I saw Satan fall like lightning from heaven.","T":"He said to them: I was watching and saw Satan fall like lightning from the sky."},
  "19": {"L":"Behold, I have given you authority to tread on serpents and scorpions, and over all the power of the enemy, and nothing shall hurt you.","M":"I have given you authority to trample on snakes and scorpions and to overcome all the power of the enemy; nothing will harm you.","T":"I have given you authority to trample on snakes and scorpions and over the full power of the enemy—nothing will harm you."},
  "20": {"L":"Nevertheless, do not rejoice in this, that the spirits are subject to you, but rejoice that your names are written in heaven.","M":"However, do not rejoice that the spirits submit to you, but rejoice that your names are written in heaven.","T":"But don't celebrate because the spirits submit to you—celebrate because your names are written in heaven."},
  "21": {"L":"In that same hour he rejoiced in the Holy Spirit and said: I thank you, Father, Lord of heaven and earth, that you have hidden these things from the wise and understanding and revealed them to little children; yes, Father, for such was your gracious will.","M":"At that time Jesus, full of joy through the Holy Spirit, said: I praise you, Father, Lord of heaven and earth, because you have hidden these things from the wise and learned, and revealed them to little children. Yes, Father, for this is what you were pleased to do.","T":"At that very moment Jesus overflowed with joy in the Holy Spirit and said: I praise you, Father, Lord of heaven and earth, because you have hidden these things from the wise and learned and revealed them to children. Yes, Father—this was your good pleasure."},
  "22": {"L":"All things have been handed over to me by my Father, and no one knows who the Son is except the Father, or who the Father is except the Son and anyone to whom the Son chooses to reveal him.","M":"All things have been committed to me by my Father. No one knows who the Son is except the Father, and no one knows who the Father is except the Son and those to whom the Son chooses to reveal him.","T":"My Father has entrusted everything to me. No one knows who the Son is except the Father, and no one knows who the Father is except the Son—and those to whom the Son chooses to reveal him."},
  "23": {"L":"Then turning to the disciples he said privately: Blessed are the eyes that see what you see!","M":"Then he turned to his disciples and said privately: Blessed are the eyes that see what you see.","T":"Turning privately to his disciples, he said: How blessed are the eyes that see what you are seeing!"},
  "24": {"L":"For I tell you that many prophets and kings desired to see what you see, and did not see it, and to hear what you hear, and did not hear it.","M":"For I tell you that many prophets and kings wanted to see what you see but did not see it, and to hear what you hear but did not hear it.","T":"I tell you, many prophets and kings longed to see what you are seeing and did not see it—to hear what you are hearing and did not hear it."},
  "25": {"L":"And behold, a lawyer stood up to put him to the test, saying: Teacher, what shall I do to inherit eternal life?","M":"On one occasion an expert in the law stood up to test Jesus. Teacher, he asked, what must I do to inherit eternal life?","T":"A legal expert stood up to test Jesus: Teacher, what must I do to inherit the life of the coming age?"},
  "26": {"L":"He said to him: What is written in the Law? How do you read it?","M":"What is written in the Law? he replied. How do you read it?","T":"Jesus replied: What does the Law say? How do you read it?"},
  "27": {"L":"And he answered: You shall love the Lord your God with all your heart and with all your soul and with all your strength and with all your mind, and your neighbor as yourself.","M":"He answered: Love the Lord your God with all your heart and with all your soul and with all your strength and with all your mind; and, love your neighbour as yourself.","T":"He answered: Love the Lord your God with all your heart, all your soul, all your strength, and all your mind—and love your neighbor as yourself."},
  "28": {"L":"And he said to him: You have answered correctly; do this, and you will live.","M":"You have answered correctly, Jesus replied. Do this and you will live.","T":"You've answered well, Jesus said. Do this and you will truly live."},
  "29": {"L":"But he, desiring to justify himself, said to Jesus: And who is my neighbor?","M":"But he wanted to justify himself, so he asked Jesus: And who is my neighbour?","T":"But wanting to justify himself, he asked: And who exactly is my neighbor?"},
  "30": {"L":"Jesus replied: A man was going down from Jerusalem to Jericho, and he fell among robbers, who stripped him and beat him and departed, leaving him half dead.","M":"In reply Jesus said: A man was going down from Jerusalem to Jericho, when he was attacked by robbers. They stripped him of his clothes, beat him and went away, leaving him half-dead.","T":"Jesus replied: A man was traveling down from Jerusalem to Jericho when robbers attacked him. They stripped him, beat him, and left him half dead on the road."},
  "31": {"L":"Now by chance a priest was going down that road, and when he saw him he passed by on the other side.","M":"A priest happened to be going down the same road, and when he saw the man, he passed by on the other side.","T":"By chance a priest came down that same road. He saw the man—and passed by on the other side."},
  "32": {"L":"So likewise a Levite, when he came to the place and saw him, passed by on the other side.","M":"So too, a Levite, when he came to the place and saw him, passed by on the other side.","T":"A Levite came the same way, looked at the man—and also passed by on the other side."},
  "33": {"L":"But a Samaritan, as he journeyed, came to where he was, and when he saw him, he had compassion.","M":"But a Samaritan, as he travelled, came where the man was; and when he saw him, he took pity on him.","T":"But a Samaritan, traveling that same road, came upon the man—and when he saw him, he was moved with deep compassion."},
  "34": {"L":"He went to him and bound up his wounds, pouring on oil and wine. Then he set him on his own animal and brought him to an inn and took care of him.","M":"He went to him and bandaged his wounds, pouring on oil and wine. Then he put the man on his own donkey, brought him to an inn and took care of him.","T":"He went to him, poured oil and wine on his wounds and bandaged them. He lifted the man onto his own animal, brought him to an inn, and cared for him through the night."},
  "35": {"L":"And the next day he took out two denarii and gave them to the innkeeper, saying: Take care of him, and whatever more you spend, I will repay you when I come back.","M":"The next day he took out two denarii and gave them to the innkeeper. Look after him, he said, and when I return, I will reimburse you for any extra expense you may have.","T":"The next morning he took out two silver coins and gave them to the innkeeper: Look after him, he said, and when I come back I'll pay you for any additional expense."},
  "36": {"L":"Which of these three, do you think, proved to be a neighbor to the man who fell among the robbers?","M":"Which of these three do you think was a neighbour to the man who fell into the hands of robbers?","T":"Now—which of these three do you think was a neighbor to the man who was attacked?"},
  "37": {"L":"He said: The one who showed him mercy. And Jesus said to him: You go, and do likewise.","M":"The expert in the law replied: The one who had mercy on him. Jesus told him: Go and do likewise.","T":"The man answered: The one who showed him mercy. Jesus said: Go and do the same."},
  "38": {"L":"Now as they went on their way, Jesus entered a village. And a woman named Martha welcomed him into her house.","M":"As Jesus and his disciples were on their way, he came to a village where a woman named Martha opened her home to him.","T":"As they continued on their way, Jesus entered a village where a woman named Martha welcomed him into her home."},
  "39": {"L":"And she had a sister called Mary, who sat at the Lord's feet and listened to his teaching.","M":"She had a sister called Mary, who sat at the Lord's feet listening to what he said.","T":"She had a sister named Mary, who sat at the Lord's feet and listened to his teaching."},
  "40": {"L":"But Martha was distracted with much serving. And she went to him and said: Lord, do you not care that my sister has left me to serve alone? Tell her then to help me.","M":"But Martha was distracted by all the preparations that had to be made. She came to him and asked: Lord, don't you care that my sister has left me to do the work by myself? Tell her to help me!","T":"Martha, though, was pulled in every direction by all the preparations. She came to Jesus and said: Lord, doesn't it concern you that my sister has left me to do all the work alone? Tell her to help me!"},
  "41": {"L":"But the Lord answered her: Martha, Martha, you are anxious and troubled about many things,","M":"Martha, Martha, the Lord answered, you are worried and upset about many things,","T":"The Lord answered: Martha, Martha—you are anxious and troubled about so many things."},
  "42": {"L":"but one thing is necessary. Mary has chosen the good portion, which will not be taken away from her.","M":"but few things are needed—or indeed only one. Mary has chosen what is better, and it will not be taken away from her.","T":"But only one thing is truly necessary. Mary has chosen the better part—and it will not be taken from her."}
 },
 "11": {
  "1": {"L":"Now Jesus was praying in a certain place, and when he finished, one of his disciples said to him: Lord, teach us to pray, as John taught his disciples.","M":"One day Jesus was praying in a certain place. When he finished, one of his disciples said to him: Lord, teach us to pray, just as John taught his disciples.","T":"Jesus was praying in a certain place. When he finished, one of his disciples said: Lord, teach us to pray, the way John taught his disciples."},
  "2": {"L":"And he said to them: When you pray, say: Father, hallowed be your name. Your kingdom come.","M":"He said to them: When you pray, say: Father, hallowed be your name, your kingdom come.","T":"He said: When you pray, say this: Father—holy is your name. May your kingdom come."},
  "3": {"L":"Give us each day our daily bread,","M":"Give us each day our daily bread.","T":"Give us each day the bread we need."},
  "4": {"L":"and forgive us our sins, for we ourselves forgive everyone who is indebted to us. And lead us not into temptation.","M":"Forgive us our sins, for we also forgive everyone who sins against us. And lead us not into temptation.","T":"Forgive us our sins—for we ourselves forgive everyone who wrongs us. And do not lead us into the time of trial."},
  "5": {"L":"And he said to them: Which of you who has a friend will go to him at midnight and say to him: Friend, lend me three loaves,","M":"Then Jesus said to them: Suppose you have a friend, and you go to him at midnight and say, Friend, lend me three loaves of bread;","T":"He said: Suppose one of you has a friend. You go to him at midnight and say: Friend, lend me three loaves of bread—"},
  "6": {"L":"for a friend of mine has arrived on a journey, and I have nothing to set before him;","M":"a friend of mine on a journey has come to me, and I have nothing to offer him.","T":"a friend of mine just arrived after a long journey and I have nothing to feed him."},
  "7": {"L":"and he will answer from within: Do not bother me; the door is now shut, and my children are with me in bed. I cannot get up and give you anything?","M":"And suppose the one inside answers: Don't bother me. The door is already locked, and my children and I are in bed. I can't get up and give you anything.","T":"And suppose the one inside says: Don't bother me—the door is already bolted, and my children are with me in bed. I can't get up to give you anything."},
  "8": {"L":"I tell you, though he will not get up and give him anything because he is his friend, yet because of his impudence he will rise and give him whatever he needs.","M":"I tell you, even though he will not get up and give you the bread because of friendship, yet because of your shameless audacity he will surely get up and give you as much as you need.","T":"I tell you: even if he won't get up out of friendship, his neighbor's bold persistence will get him up to give him as much as he needs."},
  "9": {"L":"And I tell you, ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you.","M":"So I say to you: Ask and it will be given to you; seek and you will find; knock and the door will be opened to you.","T":"So I say to you: Ask, and you will receive. Seek, and you will find. Knock, and the door will open to you."},
  "10": {"L":"For everyone who asks receives, and the one who seeks finds, and to the one who knocks it will be opened.","M":"For everyone who asks receives; the one who seeks finds; and to the one who knocks, the door will be opened.","T":"For everyone who asks receives; everyone who seeks finds; and to everyone who knocks, the door opens."},
  "11": {"L":"What father among you, if his son asks for a fish, will instead of a fish give him a serpent;","M":"Which of you fathers, if your son asks for a fish, will give him a snake instead?","T":"What father among you—if his son asks for a fish, will hand him a snake?"},
  "12": {"L":"or if he asks for an egg, will give him a scorpion?","M":"Or if he asks for an egg, will give him a scorpion?","T":"Or if he asks for an egg, will give him a scorpion?"},
  "13": {"L":"If you then, who are evil, know how to give good gifts to your children, how much more will the heavenly Father give the Holy Spirit to those who ask him!","M":"If you then, though you are evil, know how to give good gifts to your children, how much more will your Father in heaven give the Holy Spirit to those who ask him!","T":"If you, flawed as you are, know how to give good gifts to your children—how much more will your heavenly Father give the Holy Spirit to those who ask him!"},
  "14": {"L":"Now he was casting out a demon that was mute. When the demon had gone out, the mute man spoke, and the people marveled.","M":"Jesus was driving out a demon that was mute. When the demon left, the man who had been mute spoke, and the crowd was amazed.","T":"Jesus was driving out a demon that had made a man mute. When the demon came out, the man spoke—and the crowd was amazed."},
  "15": {"L":"But some of them said: He casts out demons by Beelzebul, the prince of demons,","M":"But some of them said: By Beelzebul, the prince of demons, he is driving out demons.","T":"But some of them said: He casts out demons by Beelzebul, the ruler of the demons."},
  "16": {"L":"while others, to test him, kept seeking from him a sign from heaven.","M":"Others tested him by asking for a sign from heaven.","T":"Others, trying to trap him, demanded a sign from heaven."},
  "17": {"L":"But he, knowing their thoughts, said to them: Every kingdom divided against itself is laid waste, and a divided household falls.","M":"Jesus knew their thoughts and said to them: Any kingdom divided against itself will be ruined, and a house divided against itself will fall.","T":"Knowing their thoughts, he said: Any kingdom torn apart by civil war collapses—and a house split against itself falls."},
  "18": {"L":"And if Satan also is divided against himself, how will his kingdom stand? For you say that I cast out demons by Beelzebul.","M":"If Satan is divided against himself, how can his kingdom stand? I say this because you claim that I drive out demons by Beelzebul.","T":"If Satan is divided against himself, how does his kingdom survive? And yet you say I cast out demons by Beelzebul."},
  "19": {"L":"And if I cast out demons by Beelzebul, by whom do your sons cast them out? Therefore they will be your judges.","M":"Now if I drive out demons by Beelzebul, by whom do your followers drive them out? So then, they will be your judges.","T":"If I cast out demons by Beelzebul, then by whom do your own people cast them out? They will be your judges on that account."},
  "20": {"L":"But if it is by the finger of God that I cast out demons, then the kingdom of God has come upon you.","M":"But if I drive out demons by the finger of God, then the kingdom of God has come upon you.","T":"But if I am casting out demons by the finger of God, then the kingdom of God has arrived among you."},
  "21": {"L":"When a strong man, fully armed, guards his own palace, his goods are safe;","M":"When a strong man, fully armed, guards his own house, his possessions are safe.","T":"When a fully armed strong man guards his own estate, his property is secure."},
  "22": {"L":"but when one stronger than he attacks him and overcomes him, he takes away his armor in which he trusted and divides his spoil.","M":"But when someone stronger attacks and overpowers him, he takes away the armour in which the man trusted and divides up his plunder.","T":"But when someone stronger attacks and defeats him, that conqueror strips away the armor he relied on and divides the plunder."},
  "23": {"L":"Whoever is not with me is against me, and whoever does not gather with me scatters.","M":"Whoever is not with me is against me, and whoever does not gather with me scatters.","T":"Whoever is not with me is against me—and whoever does not gather with me scatters."},
  "24": {"L":"When the unclean spirit has gone out of a person, it passes through waterless places seeking rest, and finding none it says: I will return to my house from which I came.","M":"When an impure spirit comes out of a person, it goes through arid places seeking rest and does not find it. Then it says, I will return to the house I left.","T":"When an unclean spirit leaves a person, it wanders through waterless wastelands looking for rest. Finding none, it says: I'll go back to the house I left."},
  "25": {"L":"And when it comes, it finds the house swept and put in order.","M":"When it arrives, it finds the house swept clean and put in order.","T":"When it arrives, it finds the house swept clean and tidy."},
  "26": {"L":"Then it goes and brings seven other spirits more evil than itself, and they enter and dwell there. And the last state of that person is worse than the first.","M":"Then it goes and takes seven other spirits more wicked than itself, and they go in and live there. And the final condition of that person is worse than the first.","T":"So it goes and brings back seven spirits worse than itself, and they all move in and take up residence. The final state of that person is far worse than the beginning."},
  "27": {"L":"As he said these things, a woman in the crowd raised her voice and said to him: Blessed is the womb that bore you, and the breasts at which you nursed!","M":"As Jesus was saying these things, a woman in the crowd called out: Blessed is the mother who gave you birth and nursed you.","T":"While Jesus was saying these things, a woman in the crowd called out: Blessed is the womb that bore you and the breasts that fed you!"},
  "28": {"L":"But he said: Blessed rather are those who hear the word of God and keep it!","M":"He replied: Blessed rather are those who hear the word of God and obey it.","T":"He replied: Blessed, rather, are those who hear God's word and live by it."},
  "29": {"L":"When the crowds were increasing, he began to say: This generation is an evil generation. It seeks for a sign, but no sign will be given to it except the sign of Jonah.","M":"As the crowds increased, Jesus said: This is a wicked generation. It asks for a sign, but none will be given it except the sign of Jonah.","T":"As the crowds swelled, he said: This generation is evil. It demands a sign—but no sign will be given it except the sign of Jonah."},
  "30": {"L":"For as Jonah became a sign to the people of Nineveh, so will the Son of Man be to this generation.","M":"For as Jonah was a sign to the Ninevites, so also will the Son of Man be to this generation.","T":"For just as Jonah was a sign to the Ninevites, so the Son of Man will be a sign to this generation."},
  "31": {"L":"The queen of the South will rise up at the judgment with the men of this generation and condemn them, for she came from the ends of the earth to hear the wisdom of Solomon, and behold, something greater than Solomon is here.","M":"The Queen of the South will rise at the judgment with the people of this generation and condemn them, for she came from the ends of the earth to listen to Solomon's wisdom; and now something greater than Solomon is here.","T":"The Queen of the South will stand up at the judgment alongside this generation and condemn it—she came from the far ends of the earth to hear Solomon's wisdom, and something far greater than Solomon is standing here now."},
  "32": {"L":"The men of Nineveh will rise up at the judgment with this generation and condemn it, for they repented at the preaching of Jonah, and behold, something greater than Jonah is here.","M":"The men of Nineveh will stand up at the judgment with this generation and condemn it, for they repented at the preaching of Jonah; and now something greater than Jonah is here.","T":"The people of Nineveh will stand at the judgment alongside this generation and condemn it—they turned to God at the preaching of Jonah, and something far greater than Jonah is here."},
  "33": {"L":"No one after lighting a lamp puts it in a cellar or under a basket, but on a stand, so that those who enter may see the light.","M":"No one lights a lamp and puts it in a place where it will be hidden, or under a bowl. Instead they put it on its stand, so that those who come in may see the light.","T":"No one lights a lamp and hides it in the cellar or covers it with a bowl—they put it on a stand so that everyone who enters can see the light."},
  "34": {"L":"Your eye is the lamp of your body. When your eye is healthy, your whole body is full of light, but when it is bad, your body is full of darkness.","M":"Your eye is the lamp of your body. When your eyes are healthy, your whole body also is full of light. But when they are unhealthy, your body also is full of darkness.","T":"Your eye is the lamp of your body. When your eye is clear and open, your whole body fills with light. When it is clouded, your whole body is in darkness."},
  "35": {"L":"Therefore be careful lest the light in you be darkness.","M":"See to it, then, that the light within you is not darkness.","T":"So take care that the light inside you is not actually darkness."},
  "36": {"L":"If then your whole body is full of light, having no part dark, it will be wholly bright, as when a lamp with its rays gives you light.","M":"Therefore, if your whole body is full of light, and no part of it dark, it will be just as full of light as when a lamp shines its light on you.","T":"If your whole body is filled with light—not a dark corner anywhere—it will be as bright as when a lamp illuminates you with its full radiance."},
  "37": {"L":"While Jesus was speaking, a Pharisee asked him to dine with him, so he went in and reclined at table.","M":"When Jesus had finished speaking, a Pharisee invited him to eat with him; so he went in and reclined at the table.","T":"When Jesus finished speaking, a Pharisee invited him to dine with him. He went in and reclined at the table."},
  "38": {"L":"The Pharisee was astonished to see that he did not first wash before dinner.","M":"But the Pharisee was surprised when he noticed that Jesus did not first wash before the meal.","T":"The Pharisee was astonished to see that Jesus did not wash before eating."},
  "39": {"L":"And the Lord said to him: Now you Pharisees cleanse the outside of the cup and of the dish, but inside you are full of greed and wickedness.","M":"Then the Lord said to him: Now then, you Pharisees clean the outside of the cup and dish, but inside you are full of greed and wickedness.","T":"The Lord said to him: You Pharisees—you clean the outside of the cup and the plate, but inside you are full of greed and wickedness."},
  "40": {"L":"You fools! Did not he who made the outside make the inside also?","M":"You foolish people! Did not the one who made the outside make the inside also?","T":"What fools! Didn't the same God who made the outside also make the inside?"},
  "41": {"L":"But give as alms those things that are within, and behold, everything is clean for you.","M":"But now as for what is inside you—be generous to the poor, and everything will be clean for you.","T":"Give what is inside as generosity to the poor—and everything becomes clean for you."},
  "42": {"L":"But woe to you Pharisees! For you tithe mint and rue and every herb, and neglect justice and the love of God. These you ought to have done, without neglecting the others.","M":"Woe to you Pharisees, because you give God a tenth of your mint, rue and all other kinds of garden herbs, but you neglect justice and the love of God. You should have practised the latter without leaving the former undone.","T":"But woe to you Pharisees! You meticulously tithe your mint and rue and every herb—but you pass right over justice and the love of God. You should have practiced these without abandoning the others."},
  "43": {"L":"Woe to you Pharisees! For you love the best seat in the synagogues and greetings in the marketplaces.","M":"Woe to you Pharisees, because you love the most important seats in the synagogues and respectful greetings in the market-places.","T":"Woe to you Pharisees! You love the seat of honor in the synagogues and being greeted with respect in the public squares."},
  "44": {"L":"Woe to you! For you are like unmarked graves, and people walk over them without knowing it.","M":"Woe to you, because you are like unmarked graves, which people walk over without knowing it.","T":"Woe to you—you are like unmarked graves that people walk over without knowing they're there."},
  "45": {"L":"One of the lawyers answered him: Teacher, in saying these things you insult us also.","M":"One of the experts in the law answered him: Teacher, when you say these things, you insult us also.","T":"One of the religious lawyers said: Teacher, when you say these things, you insult us as well."},
  "46": {"L":"And he said: Woe to you lawyers also! For you load people with burdens hard to bear, and you yourselves do not touch the burdens with one of your fingers.","M":"Jesus replied: And you experts in the law, woe to you, because you load people down with burdens they can hardly carry, and you yourselves will not lift one finger to help them.","T":"Jesus replied: Woe to you lawyers too! You pile crushing burdens on people's backs—and you won't lift a finger to help carry them."},
  "47": {"L":"Woe to you! For you build the tombs of the prophets whom your fathers killed.","M":"Woe to you, because you build tombs for the prophets, and it was your ancestors who killed them.","T":"Woe to you! You build monuments for the prophets—the very prophets your ancestors murdered."},
  "48": {"L":"So you are witnesses and you consent to the deeds of your fathers, for they killed them, and you build their tombs.","M":"So you testify that you approve of what your ancestors did; they killed the prophets, and you build their tombs.","T":"By doing this you are witnesses who approve of what your ancestors did—they did the killing, you do the monument-building."},
  "49": {"L":"Therefore also the Wisdom of God said: I will send them prophets and apostles, some of whom they will kill and persecute,","M":"Because of this, God in his wisdom said, I will send them prophets and apostles, some of whom they will kill and others they will persecute.","T":"This is why God's wisdom declared: I will send them prophets and messengers—some they will kill, others they will persecute."},
  "50": {"L":"so that the blood of all the prophets, shed from the foundation of the world, may be charged against this generation,","M":"Therefore this generation will be held responsible for the blood of all the prophets that has been shed since the beginning of the world,","T":"As a result, this generation will be held accountable for the blood of every prophet shed since the world began—"},
  "51": {"L":"from the blood of Abel to the blood of Zechariah, who perished between the altar and the sanctuary. Yes, I tell you, it will be required of this generation.","M":"from the blood of Abel to the blood of Zechariah, who was killed between the altar and the sanctuary. Yes, I tell you, this generation will be held responsible for it all.","T":"from Abel's blood to Zechariah's, who was killed between the altar and the sanctuary. Yes—I tell you, this generation will be held accountable for all of it."},
  "52": {"L":"Woe to you lawyers! For you have taken away the key of knowledge. You did not enter yourselves, and you hindered those who were entering.","M":"Woe to you experts in the law, because you have taken away the key to knowledge. You yourselves have not entered, and you have hindered those who were entering.","T":"Woe to you lawyers! You have taken away the key to understanding—you didn't go in yourselves and you blocked the way for those trying to enter."},
  "53": {"L":"As he went away from there, the scribes and the Pharisees began to press him hard and to provoke him to speak about many things,","M":"When Jesus went outside, the Pharisees and the teachers of the law began to oppose him fiercely and to besiege him with questions,","T":"When Jesus left that house, the religious scholars and Pharisees began pressing him hard and barraging him with questions,"},
  "54": {"L":"lying in wait for him, to catch him in something he might say.","M":"waiting to catch him in something he might say.","T":"setting traps to catch him in his own words."}
 },
 "12": {
  "1": {"L":"In the meantime, when so many thousands of the people had gathered together that they were trampling one another, he began to say to his disciples first: Beware of the leaven of the Pharisees, which is hypocrisy.","M":"Meanwhile, when a crowd of many thousands had gathered, so that they were trampling on one another, Jesus began to speak first to his disciples, saying: Be on your guard against the yeast of the Pharisees, which is hypocrisy.","T":"Meanwhile, as tens of thousands pressed in around him so tightly they were trampling each other, Jesus spoke first to his disciples: Guard yourselves against the leaven of the Pharisees—their hypocrisy."},
  "2": {"L":"Nothing is covered up that will not be revealed, or hidden that will not be known.","M":"There is nothing concealed that will not be disclosed, or hidden that will not be made known.","T":"Nothing covered will stay covered; nothing hidden will stay hidden."},
  "3": {"L":"Therefore whatever you have said in the dark shall be heard in the light, and what you have whispered in private rooms shall be proclaimed on the housetops.","M":"What you have said in the dark will be heard in the daylight, and what you have whispered in the ear in the inner rooms will be proclaimed from the roofs.","T":"What you have spoken in the dark will be heard in the light—what you have whispered in secret rooms will be proclaimed from the rooftops."},
  "4": {"L":"I tell you, my friends, do not fear those who kill the body, and after that have nothing more that they can do.","M":"I tell you, my friends, do not be afraid of those who kill the body and after that can do no more.","T":"I tell you, my friends: do not fear those who can kill the body but can do nothing more after that."},
  "5": {"L":"But I will warn you whom to fear: fear him who, after he has killed, has authority to cast into hell. Yes, I tell you, fear him!","M":"But I will show you whom you should fear: fear him who, after your body has been killed, has authority to throw you into hell. Yes, I tell you, fear him.","T":"But I will tell you whom to fear—fear the one who, after death, has authority to cast you into Gehenna. Yes, fear him."},
  "6": {"L":"Are not five sparrows sold for two pennies? And not one of them is forgotten before God.","M":"Are not five sparrows sold for two pennies? Yet not one of them is forgotten by God.","T":"Are five sparrows not sold for two pennies? And yet not one of them is forgotten by God."},
  "7": {"L":"Why, even the hairs of your head are all numbered. Fear not; you are of more value than many sparrows.","M":"Indeed, the very hairs of your head are all numbered. Don't be afraid; you are worth more than many sparrows.","T":"The very hairs of your head are all counted. Don't be afraid—you matter far more to God than many sparrows."},
  "8": {"L":"And I tell you, everyone who acknowledges me before men, the Son of Man also will acknowledge before the angels of God,","M":"I tell you, whoever publicly acknowledges me before others, the Son of Man will also acknowledge before the angels of God.","T":"I tell you: everyone who acknowledges me before others, the Son of Man will acknowledge before God's angels."},
  "9": {"L":"but the one who denies me before men will be denied before the angels of God.","M":"But whoever disowns me before others will be disowned before the angels of God.","T":"But whoever disowns me before others will be disowned before God's angels."},
  "10": {"L":"And everyone who speaks a word against the Son of Man will be forgiven, but the one who blasphemes against the Holy Spirit will not be forgiven.","M":"And everyone who speaks a word against the Son of Man will be forgiven, but anyone who blasphemes against the Holy Spirit will not be forgiven.","T":"Anyone who speaks against the Son of Man will be forgiven—but whoever blasphemes against the Holy Spirit will not be forgiven."},
  "11": {"L":"And when they bring you before the synagogues and the rulers and the authorities, do not be anxious about how you should defend yourself or what you should say,","M":"When you are brought before synagogues, rulers and authorities, do not worry about how you will defend yourselves or what you will say,","T":"When they haul you before synagogues and rulers and officials, do not worry about how to defend yourself or what to say."},
  "12": {"L":"for the Holy Spirit will teach you in that very hour what you ought to say.","M":"for the Holy Spirit will teach you at that time what you should say.","T":"The Holy Spirit will teach you in that very moment exactly what to say."},
  "13": {"L":"Someone in the crowd said to him: Teacher, tell my brother to divide the inheritance with me.","M":"Someone in the crowd said to him: Teacher, tell my brother to divide the inheritance with me.","T":"Someone in the crowd called out: Teacher, tell my brother to share the inheritance with me."},
  "14": {"L":"But he said to him: Man, who made me a judge or arbitrator over you?","M":"Jesus replied: Man, who appointed me a judge or an arbiter between you?","T":"Jesus replied: Friend, who made me a judge or mediator between you?"},
  "15": {"L":"And he said to them: Take care, and be on your guard against all covetousness, for one's life does not consist in the abundance of his possessions.","M":"Then he said to them: Watch out! Be on your guard against all kinds of greed; life does not consist in an abundance of possessions.","T":"Then he said to everyone: Watch out—be on your guard against every form of greed. A person's life does not consist in the abundance of their possessions."},
  "16": {"L":"And he told them a parable, saying: The land of a rich man produced plentifully,","M":"And he told them this parable: The ground of a certain rich man yielded an abundant harvest.","T":"He told them a parable: A certain rich man's land produced an extraordinary harvest."},
  "17": {"L":"and he thought to himself: What shall I do, for I have nowhere to store my crops?","M":"He thought to himself, What shall I do? I have no place to store my crops.","T":"He thought to himself: What am I to do? I have nowhere to store all this grain."},
  "18": {"L":"And he said: I will do this: I will tear down my barns and build larger ones, and there I will store all my grain and my goods.","M":"Then he said: This is what I'll do. I will tear down my barns and build bigger ones, and there I will store my surplus grain.","T":"Then he said: I know what I'll do—I'll tear down my barns and build bigger ones, and I'll store all my grain and goods there."},
  "19": {"L":"And I will say to my soul: Soul, you have ample goods laid up for many years; relax, eat, drink, be merry.","M":"And I'll say to myself, You have plenty of grain laid up for many years. Take life easy; eat, drink and be merry.","T":"Then I'll say to myself: You have everything you need stored up for years to come. Relax—eat, drink, enjoy life."},
  "20": {"L":"But God said to him: Fool! This night your soul is required of you, and the things you have prepared, whose will they be?","M":"But God said to him: You fool! This very night your life will be demanded from you. Then who will get what you have prepared for yourself?","T":"But God said to him: You fool! This very night your life will be required of you. Then who gets everything you have accumulated?"},
  "21": {"L":"So is the one who lays up treasure for himself and is not rich toward God.","M":"This is how it will be with whoever stores up things for themselves but is not rich towards God.","T":"That is the end of the one who piles up treasure for themselves but is not rich in the things that matter to God."},
  "22": {"L":"And he said to his disciples: Therefore I tell you, do not be anxious about your life, what you will eat, nor about your body, what you will put on.","M":"Then Jesus said to his disciples: Therefore I tell you, do not worry about your life, what you will eat; or about your body, what you will wear.","T":"He said to his disciples: This is why I tell you—don't be anxious about your life, what you'll eat, or about your body, what you'll wear."},
  "23": {"L":"For life is more than food, and the body more than clothing.","M":"For life is more than food, and the body more than clothes.","T":"Life is more than food, and the body more than clothes."},
  "24": {"L":"Consider the ravens: they neither sow nor reap, they have neither storehouse nor barn, and yet God feeds them. Of how much more value are you than the birds!","M":"Consider the ravens: they do not sow or reap, they have no storeroom or barn; yet God feeds them. And how much more valuable you are than birds!","T":"Look at the ravens—they don't plant or harvest, they have no storeroom or barn, and yet God feeds them. How much more valuable are you than birds!"},
  "25": {"L":"And which of you by being anxious can add a single hour to his span of life?","M":"Who of you by worrying can add a single hour to your life?","T":"And can any of you add a single hour to your life by worrying about it?"},
  "26": {"L":"If then you are not able to do as small a thing as that, why are you anxious about the rest?","M":"Since you cannot do this very little thing, why do you worry about the rest?","T":"If you can't manage even this smallest thing, why worry about everything else?"},
  "27": {"L":"Consider the lilies, how they grow: they neither toil nor spin, yet I tell you, even Solomon in all his glory was not arrayed like one of these.","M":"Consider how the wild flowers grow. They do not labour or spin. Yet I tell you, not even Solomon in all his splendour was dressed like one of these.","T":"Consider how the wildflowers grow—they don't work or weave. Yet I tell you, even Solomon in all his magnificence was not clothed like one of them."},
  "28": {"L":"But if God so clothes the grass, which is alive in the field today, and tomorrow is thrown into the oven, how much more will he clothe you, O you of little faith!","M":"If that is how God clothes the grass of the field, which is here today, and tomorrow is thrown into the fire, how much more will he clothe you—you of little faith!","T":"If God clothes the grass that is here today and in the fire tomorrow—how much more will he clothe you! You of such small faith."},
  "29": {"L":"And do not seek what you are to eat and what you are to drink, nor be worried.","M":"And do not set your heart on what you will eat or drink; do not worry about it.","T":"So don't set your heart on what you will eat or drink—don't be anxious about it."},
  "30": {"L":"For all the nations of the world seek after these things, and your Father knows that you need them.","M":"For the pagan world runs after all such things, and your Father knows that you need them.","T":"The nations of the world chase after all these things—but your Father knows you need them."},
  "31": {"L":"Instead, seek his kingdom, and these things will be added to you.","M":"But seek his kingdom, and these things will be given to you as well.","T":"Instead, seek his kingdom—and all these things will be given to you as well."},
  "32": {"L":"Fear not, little flock, for it is your Father's good pleasure to give you the kingdom.","M":"Do not be afraid, little flock, for your Father has been pleased to give you the kingdom.","T":"Don't be afraid, little flock—it is your Father's great delight to give you the kingdom."},
  "33": {"L":"Sell your possessions, and give to the needy. Provide yourselves with moneybags that do not grow old, with a treasure in the heavens that does not fail, where no thief approaches and no moth destroys.","M":"Sell your possessions and give to the poor. Provide purses for yourselves that will not wear out, a treasure in heaven that will never fail, where no thief comes near and no moth destroys.","T":"Sell your possessions and give to the poor. Build yourselves purses that never wear out—a treasure in heaven that never fails, where no thief can reach it and no moth destroy it."},
  "34": {"L":"For where your treasure is, there will your heart be also.","M":"For where your treasure is, there your heart will be also.","T":"For wherever your treasure is, that is where your heart will be."},
  "35": {"L":"Stay dressed for action and keep your lamps burning,","M":"Be dressed ready for service and keep your lamps burning,","T":"Stay ready for action—belts fastened, lamps burning."},
  "36": {"L":"and be like men who are waiting for their master to come home from the wedding feast, so that they may open the door to him at once when he comes and knocks.","M":"like servants waiting for their master to return from a wedding banquet, so that when he comes and knocks they can immediately open the door for him.","T":"Be like servants waiting for their master to return from a wedding banquet—so that when he comes and knocks, you open the door immediately."},
  "37": {"L":"Blessed are those servants whom the master finds awake when he comes. Truly, I say to you, he will dress himself for service and have them recline at table, and he will come and serve them.","M":"It will be good for those servants whose master finds them watching when he comes. Truly I tell you, he will dress himself to serve, will make them recline at the table and will come and wait on them.","T":"Blessed are those servants the master finds alert when he arrives. I tell you truly—he will fasten his robe, seat them at the table, and come and serve them himself."},
  "38": {"L":"If he comes in the second watch, or in the third, and finds them awake, blessed are those servants!","M":"It will be good for those servants whose master finds them ready, even if he comes in the middle of the night or towards daybreak.","T":"Whether he comes in the middle of the night or close to dawn—if he finds them awake and ready, those servants are blessed."},
  "39": {"L":"But know this, that if the master of the house had known at what hour the thief was coming, he would not have left his house to be broken into.","M":"But understand this: if the owner of the house had known at what hour the thief was coming, he would not have let his house be broken into.","T":"But know this—if the homeowner had known the hour the thief would come, he would not have allowed his house to be broken into."},
  "40": {"L":"You also must be ready, for the Son of Man is coming at an hour you do not expect.","M":"You also must be ready, because the Son of Man will come at an hour when you do not expect him.","T":"You must be ready too—because the Son of Man is coming at an hour when you least expect it."},
  "41": {"L":"Peter said: Lord, are you telling this parable for us or for everyone?","M":"Peter asked: Lord, are you telling this parable to us, or to everyone?","T":"Peter asked: Lord, is this parable meant for us, or for everyone?"},
  "42": {"L":"And the Lord said: Who then is the faithful and wise manager, whom his master will set over his household, to give them their portion of food at the proper time?","M":"The Lord answered: Who then is the faithful and wise manager, whom the master puts in charge of his servants to give them their food allowance at the proper time?","T":"The Lord replied: Who then is the faithful, wise steward—the one the master will put in charge of his household to give each person their portion at the right time?"},
  "43": {"L":"Blessed is that servant whom his master will find doing so when he comes.","M":"It will be good for that servant whom the master finds doing so when he returns.","T":"Blessed is that servant found doing this faithfully when the master arrives."},
  "44": {"L":"Truly, I say to you, he will set him over all his possessions.","M":"Truly I tell you, he will put him in charge of all his possessions.","T":"I tell you truly—he will put that servant over everything he owns."},
  "45": {"L":"But if that servant says to himself: My master is delayed in coming, and begins to beat the male and female servants, and to eat and drink and get drunk,","M":"But suppose the servant says to himself, My master is taking a long time in coming, and he then begins to beat the other servants, both men and women, and to eat and drink and get drunk.","T":"But suppose that servant says to himself: My master won't be back for a while—and begins to beat the other servants and eat and drink and get drunk."},
  "46": {"L":"the master of that servant will come on a day when he does not expect him and at an hour he does not know, and will cut him in pieces and put him with the unfaithful.","M":"The master of that servant will come on a day when he does not expect him and at an hour he is not ready for him. He will cut him to pieces and assign him a place with the unbelievers.","T":"That servant's master will come on a day and at an hour he is not expecting—and will cut him to pieces and assign him a place among the faithless."},
  "47": {"L":"And that servant who knew his master's will but did not get ready or act according to his will, will receive a severe beating.","M":"The servant who knows the master's will and does not get ready or does not do what the master wants will be beaten with many blows.","T":"The servant who knew the master's will but made no preparation and did not act on it will receive a severe punishment."},
  "48": {"L":"But the one who did not know, and did what deserved a beating, will receive a light beating. Everyone to whom much was given, of him much will be required, and from him to whom they entrusted much, they will demand the more.","M":"But the one who does not know and does things deserving punishment will be beaten with few blows. From everyone who has been given much, much will be demanded; and from the one who has been entrusted with much, much more will be asked.","T":"The one who acted badly without knowing better will be punished less severely. From everyone who has been given much, much will be required—and from those entrusted with more, even more will be expected."},
  "49": {"L":"I came to cast fire on the earth, and would that it were already kindled!","M":"I have come to bring fire on the earth, and how I wish it were already kindled!","T":"I came to throw fire on the earth—and how I wish it were already blazing!"},
  "50": {"L":"I have a baptism to be baptized with, and how great is my distress until it is accomplished!","M":"But I have a baptism to undergo, and what constraint I am under until it is completed!","T":"I have a baptism to undergo—and what anguish grips me until it is completed!"},
  "51": {"L":"Do you think that I have come to give peace on earth? No, I tell you, but rather division.","M":"Do you think I came to bring peace on earth? No, I tell you, but division.","T":"Do you think I came to bring peace to the earth? No—I came to bring division."},
  "52": {"L":"For from now on in one house there will be five divided, three against two and two against three.","M":"From now on there will be five in one family divided against each other, three against two and two against three.","T":"From now on, five in one household will be divided—three against two and two against three."},
  "53": {"L":"They will be divided, father against son and son against father, mother against daughter and daughter against mother, mother-in-law against her daughter-in-law and daughter-in-law against mother-in-law.","M":"They will be divided, father against son and son against father, mother against daughter and daughter against mother, mother-in-law against daughter-in-law and daughter-in-law against mother-in-law.","T":"Father against son, son against father; mother against daughter, daughter against mother; mother-in-law against daughter-in-law, daughter-in-law against mother-in-law."},
  "54": {"L":"He also said to the crowds: When you see a cloud rising in the west, you say at once: A shower is coming. And so it happens.","M":"He said to the crowd: When you see a cloud rising in the west, immediately you say, It's going to rain, and it does.","T":"He said to the crowds: When you see a cloud building in the west, you immediately say: Rain is coming—and it does."},
  "55": {"L":"And when you see the south wind blowing, you say: There will be scorching heat, and it happens.","M":"And when the south wind blows, you say, It's going to be hot, and it is.","T":"And when the south wind blows, you say: It will be scorching—and it is."},
  "56": {"L":"You hypocrites! You know how to interpret the appearance of earth and sky, but why do you not know how to interpret the present time?","M":"Hypocrites! You know how to interpret the appearance of the earth and the sky. How is it that you don't know how to interpret this present time?","T":"Hypocrites! You can read the face of earth and sky—why can't you read what this moment means?"},
  "57": {"L":"And why do you not judge for yourselves what is right?","M":"Why don't you judge for yourselves what is right?","T":"Why don't you judge for yourselves what the right thing is?"},
  "58": {"L":"As you go with your accuser before the magistrate, make an effort to settle with him on the way, lest he drag you to the judge, and the judge hand you over to the officer, and the officer put you in prison.","M":"As you are going with your adversary to the magistrate, try hard to be reconciled on the way, or your adversary may drag you off to the judge, and the judge turn you over to the officer, and the officer throw you into prison.","T":"When you are on your way to court with your opponent, make every effort to settle matters before you get there—or he may drag you before the judge, the judge hand you to the officer, and the officer throw you in prison."},
  "59": {"L":"I tell you, you will never get out until you have paid the very last penny.","M":"I tell you, you will not get out until you have paid the last penny.","T":"I tell you, you will not get out until you have paid to the very last coin."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'luke')
        for ch, verses in LUKE_10_12.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'luke', data)
    print('Luke chapters 10-12 written.')

if __name__ == '__main__':
    main()
